        let mut amount: Value = self.safe_number_k(transfer.clone(), "amt", &[]);
        let mut fromAccountId: Value = self.safe_string_k(transfer.clone(), "from", &[]);
        let mut toAccountId: Value = self.safe_string_k(transfer.clone(), "to", &[]);
